// Extract data from webhook
const transcript = $input.item.json.body.transcript;
const speaker = $input.item.json.body.speaker;
const timestamp = $input.item.json.body.timestamp;
const conversationHistory = $input.item.json.body.conversationHistory || [];

// Build context from conversation history
let contextText = "";
if (conversationHistory.length > 0) {
  contextText = "Recent conversation:\n";
  conversationHistory.slice(-5).forEach(entry => {
    contextText += `${entry.speaker}: ${entry.text}\n`;
  });
}

// Prepare data for OpenAI
return {
  json: {
    transcript,
    speaker,
    timestamp,
    conversationHistory,
    contextText,
    currentMessage: `${speaker}: ${transcript}`
  }
};

