parameters.functionCode:
// Parse OpenAI response
const openaiResponse = $input.item.json.choices[0].message.content;

// Try to parse as JSON
let coaching;
try {
  coaching = JSON.parse(openaiResponse);
} catch (error) {
  // If not valid JSON, create a simple response
  coaching = {
    analysis: "AI analysis in progress",
    suggestions: [openaiResponse],
    priority: "normal",
    category: "info"
  };
}

// Return formatted response for extension
return {
  json: {
    success: true,
    coaching: {
      analysis: coaching.analysis || "Analysis not available",
      suggestions: coaching.suggestions || [],
      priority: coaching.priority || "normal",
      category: coaching.category || "suggestion",
      timestamp: Date.now()
    }
  }
};

// Log error for debugging
const error = $input.item.json.error || 'Unknown error';

console.log('Coaching AI Error:', error);

// Return fallback response
return {
  json: {
    success: false,
    coaching: {
      analysis: "AI coaching temporarily unavailable",
      suggestions: [
        "Continue with your current approach",
        "Listen actively to the prospect's needs",
        "Build rapport and trust"
      ],
      priority: "normal",
      category: "info",
      timestamp: Date.now()
    },
    error: error
  }
};
